def main():
    out_dir = Path(sys.argv[1]) if len(sys.argv) > 1 else Path("data")
    out_dir.mkdir(parents=True, exist_ok=True)

    mal_path = out_dir / "malicious.json"
    ben_path = out_dir / "benign.json"

    with open(mal_path, "w", encoding="utf-8") as f:
        json.dump(MALICIOUS, f, indent=2, ensure_ascii=False)
    print(f"[OK] Wrote {len(MALICIOUS)} malicious prompts -> {mal_path}")

    with open(ben_path, "w", encoding="utf-8") as f:
        json.dump(BENIGN, f, indent=2, ensure_ascii=False)
    print(f"[OK] Wrote {len(BENIGN)} benign prompts -> {ben_path}")

    print("\nDomain breakdown (malicious):")
    for domain, count in sorted(Counter(p["domain"] for p in MALICIOUS).items()):
        print(f"  {domain:15s}: {count} prompts")
    print(f"\n  Total malicious : {len(MALICIOUS)}")
    print(f"  Total benign    : {len(BENIGN)}")


if __name__ == "__main__":
    main()